1	use core::{
2	    mem,
3	    sync::atomic::{self, AtomicUsize, Ordering},
4	};
5	
6	use crate::Backoff;
7	
8	/// A simple stamped lock.
9	pub(crate) struct SeqLock {
10	    /// The current state of the lock.
11	    ///
12	    /// All bits except the least significant one hold the current stamp. When locked, the state
13	    /// equals 1 and doesn't contain a valid stamp.
14	    state: AtomicUsize,
15	}
16	
17	impl SeqLock {
18	    pub(crate) const fn new() -> Self {
19	        Self {
20	            state: AtomicUsize::new(0),
21	        }
22	    }
23	
24	    /// If not locked, returns the current stamp.
25	    ///
26	    /// This method should be called before optimistic reads.
27	    #[inline]
28	    pub(crate) fn optimistic_read(&self) -> Option<usize> {
29	        let state = self.state.load(Ordering::Acquire);
30	        if state == 1 { None } else { Some(state) }
31	    }
32	
33	    /// Returns `true` if the current stamp is equal to `stamp`.
34	    ///
35	    /// This method should be called after optimistic reads to check whether they are valid. The
36	    /// argument `stamp` should correspond to the one returned by method `optimistic_read`.
37	    #[inline]
38	    pub(crate) fn validate_read(&self, stamp: usize) -> bool {
39	        atomic::fence(Ordering::Acquire);
40	        self.state.load(Ordering::Relaxed) == stamp
41	    }
42	
43	    /// Grabs the lock for writing.
44	    #[inline]
45	    pub(crate) fn write(&'static self) -> SeqLockWriteGuard {
46	        let backoff = Backoff::new();
47	        loop {
48	            let previous = self.state.swap(1, Ordering::Acquire);
49	
50	            if previous != 1 {
51	                atomic::fence(Ordering::Release);
52	
53	                return SeqLockWriteGuard {
54	                    lock: self,
55	                    state: previous,
56	                };
57	            }
58	
59	            backoff.snooze();
60	        }
61	    }
62	}
63	
64	/// An RAII guard that releases the lock and increments the stamp when dropped.
65	pub(crate) struct SeqLockWriteGuard {
66	    /// The parent lock.
67	    lock: &'static SeqLock,
68	
69	    /// The stamp before locking.
70	    state: usize,
71	}
72	
73	impl SeqLockWriteGuard {
74	    /// Releases the lock without incrementing the stamp.
75	    #[inline]
76	    pub(crate) fn abort(self) {
77	        self.lock.state.store(self.state, Ordering::Release);
78	
79	        // We specifically don't want to call drop(), since that's
80	        // what increments the stamp.
81	        mem::forget(self);
82	    }
83	}
84	
85	impl Drop for SeqLockWriteGuard {
86	    #[inline]
87	    fn drop(&mut self) {
88	        // Release the lock and increment the stamp.
89	        self.lock
90	            .state
91	            .store(self.state.wrapping_add(2), Ordering::Release);
92	    }
93	}
94	
